pub async fn get_integrations(
    State(state): State<AppState>,
    Extension(auth): Extension<AuthInfo>,
) -> Result<Json<IntegrationStatusResponse>, (StatusCode, Json<serde_json::Value>)> {
    if !is_org_owner(&state.db, auth.organization_id, auth.user_id).await {
        return Err((
            StatusCode::FORBIDDEN,
            Json(serde_json::json!({
                "error": { "code": "FORBIDDEN", "message": "Admin role required" }
            })),
        ));
    }

    let config = &state.integrations_config;
    let env = std::env::var("APP_ENV").unwrap_or_else(|_| "dev".to_string());

    let mut points = Vec::new();

    // payroll.payday_filing
    let pdf = &config.payroll.payday_filing;
    let reachable = if pdf.enabled {
        Some(ping_http(&pdf.endpoint).await)
    } else {
        None
    };
    let last_sync = if pdf.enabled {
        ird_last_sync(&state.db).await
    } else {
        None
    };
    points.push(IntegrationPoint {
        domain: "payroll",
        capability: "payday_filing",
        provider: pdf.provider.clone(),
        enabled: pdf.enabled,
        endpoint: Some(pdf.endpoint.clone()),
        reachable,
        last_sync,
    });

    // payroll.notifications
    let notif = &config.payroll.notifications;
    points.push(IntegrationPoint {
        domain: "payroll",
        capability: "notifications",
        provider: notif.provider.clone(),
        enabled: notif.enabled,
        endpoint: None,
        reachable: None,
        last_sync: None,
    });

    // common.media
    let media = &config.common.media;
    points.push(IntegrationPoint {
        domain: "common",
        capability: "media",
        provider: media.provider.clone(),
        enabled: media.enabled,
        endpoint: Some(media.base_url.clone()),
        reachable: None,
        last_sync: None,
    });

    Ok(Json(IntegrationStatusResponse {
        environment: env,
        integration_points: points,
    }))
}
